  dynamic _sanitizeData(dynamic data) {
    if (data == null) return null;
    
    if (data is Map) {
      final sanitized = <String, dynamic>{};
      data.forEach((key, value) {
        final keyStr = key.toString().toLowerCase();
        if (_sensitiveFields.any((field) => keyStr.contains(field.toLowerCase()))) {
          sanitized[key] = '[REDACTED]';
        } else {
          sanitized[key] = _sanitizeData(value);
        }
      });
      return sanitized;
    } else if (data is List) {
      return data.map((item) => _sanitizeData(item)).toList();
    } else if (data is String) {
      return _sanitizeString(data);
    }
    
    return data;
  }

  String _sanitizeString(String value) {
    if (value.length > 1000) {
      return '${value.substring(0, 1000)}... [TRUNCATED]';
    }
    return value;
  }

  Map<String, String>? _sanitizeHeaders(Map<String, String>? headers) {
    if (headers == null) return null;
    
    final sanitized = <String, String>{};
    headers.forEach((key, value) {
      final keyLower = key.toLowerCase();
      if (keyLower.contains('authorization') || 
          keyLower.contains('token') || 
          keyLower.contains('api-key')) {
        sanitized[key] = '[REDACTED]';
      } else {
        sanitized[key] = value;
      }
    });
    return sanitized;
  }

  String _sanitizeUrl(String url) {
    try {
      final uri = Uri.parse(url);
      if (uri.hasQuery) {
        final sanitizedParams = <String, String>{};
        uri.queryParameters.forEach((key, value) {
          final keyLower = key.toLowerCase();
          if (_sensitiveFields.any((field) => keyLower.contains(field.toLowerCase()))) {
            sanitizedParams[key] = '[REDACTED]';
          } else {
            sanitizedParams[key] = value;
          }
        });
        return uri.replace(queryParameters: sanitizedParams).toString();
      }
      return url;
    } catch (e) {
      return url;
    }
  }

  String _maskString(String value) {
    if (value.length <= 2) return '**';
    return '${value[0]}${'*' * (value.length - 2)}${value[value.length - 1]}';
  }

  String _maskEmail(String email) {
    final parts = email.split('@');
    if (parts.length != 2) return '[REDACTED]';
    return '${_maskString(parts[0])}@${parts[1]}';
  }
